-- 105_ingredients_for_indian_expansion.sql
-- Ingredients for the 92 Indian recipes added in 101_*.sql.
-- 6-8 key ingredients per recipe — enough for shopping-list auto-generation.
-- Idempotent: skips inserts that would duplicate (recipe_id, ingredient_name).

BEGIN;

-- Make the load idempotent by deleting any pre-existing rows for these
-- recipes first (the table has no compound unique key, so ON CONFLICT can't
-- target a duplicate row).
DELETE FROM recipe_ingredients WHERE recipe_id::text LIKE 'c0000%';

